const query = $input.first().json.query ?? {};
const patientId      = query.patient_id || null;
const daysOverdue    = parseInt(query.days_overdue || '3', 10);
const autoMarkMissed = query.auto_mark_missed === 'true' || query.auto_mark_missed === true;
return [{ json: { patientId, daysOverdue, autoMarkMissed } }];

const rows = $input.all();
// Filter out UPDATE result rows (no sequence_id), keep SELECT rows
const abandoned = rows
  .filter(r => r.json.sequence_id)
  .map(r => ({
    sequence_id:      r.json.sequence_id,
    patient_id:       r.json.patient_id,
    patient_name:     r.json.patient_name || null,
    service_name:     r.json.service_name,
    seq_step_id:      r.json.seq_step_id,
    step_position:    r.json.step_position,
    missed_step_name: r.json.missed_step_name,
    missed_days_ago:  parseInt(r.json.missed_days_ago, 10) || 0,
  }));

return [{ json: { abandoned, total: abandoned.length } }];
